Greedy insertion with nearest-neighbor heuristic: iterate orders sequentially, evaluate all feasible routes, choose minimal marginal cost increase, fallback to empty assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for jj := 0; jj < orderCount; jj++ {
		bestIdx := -1
		bestDelta := 1e308
		originalCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		insertedOrderID := total_ship + jj

		feasibleFound := false

		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			ok := dispatch.Assigns[ii].AddShip(insertedOrderID, oris[jj], dess[jj])
			if ok {
				oldCost := originalCosts[ii]
				newCost := dispatch.Assigns[ii].Cost
				delta := newCost - oldCost
				if delta >= 0 && delta < bestDelta {
					bestDelta = delta
					bestIdx = ii
					feasibleFound = true
				}
				dispatch.Assigns[ii].RemoveShip(insertedOrderID)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		if feasibleFound {
			dispatch.Assigns[bestIdx].AddShip(insertedOrderID, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			fallbackInserted := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if dispatch.Assigns[ii].StationsLen == 0 {
					ok := dispatch.Assigns[ii].AddShip(insertedOrderID, oris[jj], dess[jj])
					if ok {
						dispatch.Assigns[ii].GenRoute()
						fallbackInserted = true
						break
					}
				}
			}
			if !fallbackInserted {
				if dispatch.AssignsLen < MAXASSIGNS {
					ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(insertedOrderID, oris[jj], dess[jj])
					if ok {
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
						dispatch.AssignsLen++
						fallbackInserted = true
					}
				}
			}
			if !fallbackInserted && dispatch.AssignsLen < MAXASSIGNS {
				ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(insertedOrderID, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

